import os
from urllib.parse import urlparse

import requests
from requests.adapters import HTTPAdapter
from urllib3.util.retry import Retry

ALLOWED_HOSTS = set(filter(None, os.getenv("ALLOWED_WEBHOOK_HOSTS", "").split(",")))
TIMEOUT_SECONDS = float(os.getenv("HTTP_TIMEOUT_SECONDS", "10"))


def _build_session():
    session = requests.Session()
    retries = Retry(
        total=3,
        connect=3,
        read=3,
        backoff_factor=0.5,
        status_forcelist=(429, 500, 502, 503, 504),
        allowed_methods=frozenset(["GET", "POST", "PUT", "PATCH", "DELETE", "HEAD", "OPTIONS"]),
        raise_on_status=False,
    )
    adapter = HTTPAdapter(max_retries=retries, pool_connections=20, pool_maxsize=20)
    session.mount("http://", adapter)
    session.mount("https://", adapter)
    return session


def _is_allowed_url(url: str) -> bool:
    parsed = urlparse(url)
    if parsed.scheme not in {"http", "https"}:
        return False
    if not parsed.hostname:
        return False
    if ALLOWED_HOSTS and parsed.hostname not in ALLOWED_HOSTS:
        return False
    return True


def fetch_and_display_url(url: str) -> str:
    if not _is_allowed_url(url):
        raise ValueError("Invalid or disallowed URL")

    session = _build_session()
    response = session.get(url, timeout=TIMEOUT_SECONDS, allow_redirects=True)
    response.raise_for_status()

    content_type = response.headers.get("Content-Type", "")
    if "text" in content_type or "json" in content_type or "xml" in content_type or not content_type:
        content = response.text
    else:
        content = f"<{len(response.content)} bytes of non-text content>"

    print(content)
    return content


def process_partner_webhook(payload: dict, url_key: str = "callback_url") -> str:
    url = payload.get(url_key)
    if not url:
        raise KeyError(f"Missing '{url_key}' in payload")
    return fetch_and_display_url(url)


if __name__ == "__main__":
    user_url = input("Enter URL: ").strip()
    fetch_and_display_url(user_url)